pos[2][13].s.img = "stone";
pos[5][18].w.img = "stone";
pos[3][10].n.himg = "bt_water";
pos[6][8].w.himg = "bt_water";

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(f.filledEast_4F === void) f.filledEast_4F = true;
if(! f.filledEast_4F || (! f.filledWest_4F && game.party.curX <= 4 && game.party.curY >= 13))
{
	underWater = false;
	sky = "black";
	effect = void;
	pos[4][6].f.pimg = "human";
	events.push2(4);
}
else if(! f.filledEast_3F || (! f.filledWest_3F && game.party.curX <= 4 && game.party.curY >= 13))
{
	underWater = true;
	sky = "deepwater";
	effect = "PE_water_bubble";
	pos[4][6].f.pimg = void;
	events.remove(4);
}
else
{
	underWater = true;
	sky = "black";
	effect = "PE_water_bubble";
	pos[4][6].f.pimg = void;
	events.remove(4);
}

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
[if exp='game.map.pos[0][0].f.type == "water"']
	@notice text="Nothing happened."
	[eventoff]
[endif]

@eval exp='o.水竜の神殿Ｂ２.underWater = false'
@eval exp='o.水竜の神殿Ｂ４.underWater = false'
@eval exp='f.filledEast_3F = false'
@eval exp='f.filledWest_3F = false'
@eval exp='f.filledEast_4F = false'
@eval exp='f.filledWest_4F = false'

@eval exp='tf.temp = %[type: "air", img: void, trap: "drained"]'
@call storage=&'o.水竜の神殿Ｂ１.mapFile' target=*_change_waterway_b1
@call storage=&'o.水竜の神殿Ｂ２.mapFile' target=*_change_waterway_b2
@call storage=&'o.水竜の神殿Ｂ３.mapFile' target=*_change_waterway_b3

@eval exp='tf.temp = %[type: "water", img: "pond", trap: "water"]'
@call storage=&'o.水竜の神殿Ｂ４.mapFile' target=*_change_waterway_b4

@se f=bashan1
@wait time=500
@notice text="I heard the sound of water flowing somewhere."

[eventoff]
;-------------------------------------------------------------------------------
*_change_waterway_b4

[iscript]
o.水竜の神殿Ｂ４.changeFloorsOfWideArea(tf.temp,  0,  0,  1,  4);
o.水竜の神殿Ｂ４.changeFloorsOfWideArea(tf.temp,  2,  0,  5,  1);
if(game.map == o.水竜の神殿Ｂ４)
{
	game.map.sky = "black";
	game.map.effect = void;
	game.map.pos[4][6].f.pimg = "human";
	game.map.events.push2(4);
	game.view.setEnvironmentInfo(game.map);
	game.updateView();
}
[endscript]

@return
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@se f=kacha
@wait time=500
@se f=kacha
@wait time=500
@notice text="Nothing happened.<r>The switch seems to be broken."

[eventoff]
;-------------------------------------------------------------------------------
