*event_4
;[exp] ! map.underWater && party.lastIsMove

@fg c=9016 left=450
[texton w=1]
[ドナ f=06]「...I am a wandering peddler. Traveler, would you like to take a look at my wares?」[k]
[textoff]
@question title="Take a look?"
@clf
[eventoff cond='! tf.result']
@shop name=ドナの行商２
[texton w=0]
[ドナ]「Visit again～!」[k]
[textoff]

